module RefModule(
	input clk,
	input reset,
	output [3:0] count);reg [3:0] counter;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt)
	if (reset)
		counter <= 4'b0000;
	else
		counter <= counter + 1;

assign count = counter;

endmodule
